#[test]
fn test_generate_pad_before_suffix_border() {
    test_log!("START", "Testing PadBeforeSuffixBorder generation");

    // Setup: Line with content shorter than target column
    let line = AnalyzedLine {
        original: "| Hello |".to_string(),
        kind: LineKind::Strong,
        suffix_border: Some(SuffixBorder { col: 8, char: '|' }),
        left_border_pos: Some(0),
    };
    let target_col = 20;

    test_log!("INPUT", "Line: '{}', target_col: {}", line.original, target_col);
    test_log!("INPUT", "suffix_border col: {}, char: '{}'", 
        line.suffix_border.as_ref().unwrap().col,
        line.suffix_border.as_ref().unwrap().char);

    let revisions = generate_revisions(&line, target_col);

    test_log!("OUTPUT", "Generated {} revision(s)", revisions.len());
    for (i, rev) in revisions.iter().enumerate() {
        test_log!("OUTPUT", "  Revision {}: {:?}", i, rev);
    }

    assert_eq!(revisions.len(), 1, "Should generate exactly one PadBeforeSuffixBorder");
    match &revisions[0] {
        Revision::PadBeforeSuffixBorder { spaces_to_add, .. } => {
            let expected_spaces = target_col - 8;
            assert_eq!(*spaces_to_add, expected_spaces, 
                "Should add {} spaces", expected_spaces);
            test_log!("PASS", "Correct spaces_to_add: {}", spaces_to_add);
        }
        _ => panic!("Expected PadBeforeSuffixBorder revision"),
    }

    test_log!("END", "Test PASSED");
}
```

