## TEST SECTION 2: Revision Scoring Tests

### Test Case 2.1: Score Strong Lines Higher
```rust
#[test]
fn test_score_strong_line_revision() {
    test_log!("START", "Testing that Strong line revisions score higher");

    let strong_line = AnalyzedLine {
        original: "+----------+".to_string(),
        kind: LineKind::Strong,
        suffix_border: Some(SuffixBorder { col: 11, char: '+' }),
        left_border_pos: Some(0),
    };

    let weak_line = AnalyzedLine {
        original: "| content |".to_string(),
        kind: LineKind::Weak,
        suffix_border: Some(SuffixBorder { col: 10, char: '|' }),
        left_border_pos: Some(0),
    };

    let strong_revision = Revision::PadBeforeSuffixBorder {
        line_idx: 0,
        spaces_to_add: 5,
        suffix_char: '+',
    };

    let weak_revision = Revision::PadBeforeSuffixBorder {
        line_idx: 1,
        spaces_to_add: 5,
        suffix_char: '|',
    };

    let strong_score = score_revision(&strong_revision, &strong_line);
    let weak_score = score_revision(&weak_revision, &weak_line);

    test_log!("SCORE", "Strong line revision score: {:.3}", strong_score);
    test_log!("SCORE", "Weak line revision score: {:.3}", weak_score);

    assert!(strong_score >= weak_score, 
        "Strong line revision ({}) should score >= weak line revision ({})",
        strong_score, weak_score);

    test_log!("END", "Test PASSED");
}
```

