#[test]
fn test_line_beyond_target_no_truncation() {
    test_log!("START", "Testing that lines beyond target are never truncated");

    let line = AnalyzedLine {
        original: "| Very long content that exceeds target |".to_string(),
        kind: LineKind::Strong,
        suffix_border: Some(SuffixBorder { col: 40, char: '|' }),
        left_border_pos: Some(0),
    };
    let target_col = 20; // Less than current suffix position

    test_log!("INPUT", "Line suffix at col {}, target {}", 40, target_col);

    let revisions = generate_revisions(&line, target_col);

    test_log!("OUTPUT", "Revisions generated: {}", revisions.len());

    // Monotone edit rule: never remove content
    for rev in &revisions {
        match rev {
            Revision::PadBeforeSuffixBorder { spaces_to_add, .. } => {
                assert!(*spaces_to_add >= 0, "Should never have negative padding");
            }
            _ => {}
        }
    }

    // Should generate no revisions since line already exceeds target
    assert!(revisions.is_empty(), 
        "Should not generate revisions when line exceeds target (monotone edits)");

    test_log!("END", "Test PASSED");
}
```

