 {"id":"bd-3i9","title":"Add git pre-commit hook installer","description":"## Purpose
Add a command to install a git pre-commit hook that automatically checks/fixes diagram alignment. Makes aadc a natural part of the development workflow.

## CLI Interface

```bash
# Install hook in current repo
aadc hook install

# Install with check-only mode (no auto-fix)
aadc hook install --check-only

# Install with auto-fix
aadc hook install --auto-fix

# Uninstall hook
aadc hook uninstall

# Show hook status
aadc hook status
```

## Implementation

### Subcommand Definition (clap)
```rust
#[derive(Subcommand, Debug)]
enum Commands {
    /// Manage git pre-commit hook
    Hook {
        #[command(subcommand)]
        action: HookAction,
    },
    // ... other subcommands or main processing
}

#[derive(Subcommand, Debug)]
enum HookAction {
    /// Install pre-commit hook
    Install {
        /// Only check, don't auto-fix
        #[arg(long)]
        check_only: bool,

        /// Auto-fix diagrams before commit
        #[arg(long, conflicts_with = "check_only")]
        auto_fix: bool,

        /// File patterns to check (default: *.md *.txt)
        #[arg(long, value_delimiter = ',')]
        patterns: Option<Vec<String>>,
    },
    /// Uninstall pre-commit hook
    Uninstall,
    /// Show hook status
    Status,
}
```

### Hook Script (Check Mode)
```bash
#!/usr/bin/env bash
# aadc pre-commit hook (check mode)
# Generated by: aadc hook install --check-only

set -e

PATTERNS="*.md *.txt"

# Get staged files matching patterns
staged_files() {
    for pattern in $PATTERNS; do
        git diff --cached --name-only --diff-filter=ACM | grep -E "${pattern//\*/.*}" || true
    done | sort -u
}

files=$(staged_files)
if [[ -z "$files" ]]; then
    exit 0
fi

failed=0
for file in $files; do
    if ! aadc --dry-run "$file" > /dev/null 2>&1; then
        echo "Diagram alignment needed: $file"
        ((failed++))
    fi
done

if [[ $failed -gt 0 ]]; then
    echo ""
    echo "Run 'aadc -i <file>' to fix, or 'git commit --no-verify' to skip"
    exit 1
fi
```

### Hook Script (Auto-fix Mode)
```bash
#!/usr/bin/env bash
# aadc pre-commit hook (auto-fix mode)
# Generated by: aadc hook install --auto-fix

set -e

PATTERNS="*.md *.txt"

# Get staged files matching patterns
staged_files() {
    for pattern in $PATTERNS; do
        git diff --cached --name-only --diff-filter=ACM | grep -E "${pattern//\*/.*}" || true
    done | sort -u
}

files=$(staged_files)
if [[ -z "$files" ]]; then
    exit 0
fi

modified=0
for file in $files; do
    if ! aadc --dry-run "$file" > /dev/null 2>&1; then
        echo "Auto-fixing diagrams: $file"
        aadc -i "$file"
        git add "$file"
        ((modified++))
    fi
done

if [[ $modified -gt 0 ]]; then
    echo "Auto-fixed $modified file(s)"
fi
```

### Installation Logic
```rust
fn install_hook(action: &HookInstall) -> anyhow::Result<()> {
    // Find git root
    let git_dir = find_git_dir()?;
    let hooks_dir = git_dir.join("hooks");
    let hook_path = hooks_dir.join("pre-commit");

    // Check for existing hook
    if hook_path.exists() {
        let content = fs::read_to_string(&hook_path)?;
        if content.contains("# aadc pre-commit hook") {
            println!("aadc hook already installed");
            return Ok(());
        }
        // Backup existing hook
        let backup = hook_path.with_extension("pre-aadc");
        fs::rename(&hook_path, &backup)?;
        println!("Backed up existing hook to: {}", backup.display());
    }

    // Generate hook script
    let script = if action.auto_fix {
        generate_autofix_hook(&action.patterns)
    } else {
        generate_check_hook(&action.patterns)
    };

    // Write hook
    fs::write(&hook_path, script)?;

    // Make executable
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        let mut perms = fs::metadata(&hook_path)?.permissions();
        perms.set_mode(0o755);
        fs::set_permissions(&hook_path, perms)?;
    }

    println!("Installed aadc pre-commit hook: {}", hook_path.display());
    Ok(())
}
```

