# Output options
# verbose = false
# color = "auto"  # auto | always | never
# json = false

# Backup options (for --in-place)
# backup = false
# backup_suffix = ".bak"

# Recursive mode defaults
# recursive = false
# glob = "*.txt,*.md"
# gitignore = true
# max_depth = 0

# Watch mode debounce (milliseconds)
# debounce_ms = 500

# Force processing of low-confidence blocks
# all = false
